34	function constraint_to_multiple_of(val, multiple, minVal = 0, maxVal = null) {
35	    const a = val / multiple;
36	    let x = bankers_round(a) * multiple;
37	
38	    if (maxVal !== null && x > maxVal) {
39	        x = Math.floor(a) * multiple;
40	    }
41	
42	    if (x < minVal) {
43	        x = Math.ceil(a) * multiple;
44	    }
45	
46	    return x;
