122	
123	            } else {
124	                // Get most probable class
125	                let maxIndex = max(logit.data)[1];
126	
127	                if (maxIndex === num_classes - 1) {
128	                    // This is the background class, skip it
129	                    continue;
130	                }
131	                // Compute softmax over classes
132	                probs = softmax(logit.data);
133	
134	                if (probs[maxIndex] < threshold) {
135	                    continue;
136	                }
137	                indices.push(maxIndex);
138	            }
139	
140	            for (const index of indices) {
141	
142	                // Some class has a high enough probability
143	                /** @type {number[]} */
144	                let box = bbox[j].data;
145	
146	                // convert to [x0, y0, x1, y1] format
147	                box = center_to_corners_format(box)
