### 5. **Processor Architecture for Image+Text**

**Location:** `/src/base/processing_utils.js` (lines 38-133)

The `Processor` class combines multiple components:

```javascript
export class Processor extends Callable {
    static classes = [
        'image_processor_class',
        'tokenizer_class',
        'feature_extractor_class',
    ]

    get image_processor() { return this.components.image_processor; }
    get tokenizer() { return this.components.tokenizer; }
    get feature_extractor() { return this.components.feature_extractor; }

    async _call(input, ...args) {
        // Falls through: image_processor → feature_extractor → tokenizer
        for (const item of [this.image_processor, this.feature_extractor, this.tokenizer]) {
            if (item) return item(input, ...args);
        }
    }
}
```

**Key Methods:**
- `apply_chat_template()`: Format messages with chat templates (useful for multimodal models)
- `batch_decode()` / `decode()`: Proxy to tokenizer for decoding
- `from_pretrained()`: Load processor with appropriate image processor + tokenizer combo

---

### 6. **Multimodal Processor Examples**

**LLaVA Processor** (`/src/models/llava/processing_llava.js`):

```javascript
export class LlavaProcessor extends Processor {
    static tokenizer_class = AutoTokenizer
    static image_processor_class = AutoImageProcessor
    static uses_processor_config = true;

    async _call(images, text = null, kwargs = {}) {
        const image_inputs = await this.image_processor(images, kwargs);

        if (text) {
            // Calculate number of image tokens based on image resolution
            const [height, width] = image_inputs.pixel_values.dims.slice(-2);
            const num_image_tokens = Math.floor(height / patch_size) * 
                                     Math.floor(width / patch_size) + 
                                     num_additional_image_tokens;

            // Replace image token placeholder with actual token count
            text = text.replace(image_token, image_token.repeat(num_image_tokens));
        }

        const text_inputs = text ? this.tokenizer(text, kwargs) : {};

        return { ...image_inputs, ...text_inputs };
    }
}
```

**Qwen2-VL Processor** (`/src/models/qwen2_vl/processing_qwen2_vl.js`):

```javascript
export class Qwen2VLProcessor extends Processor {
    static image_processor_class = AutoImageProcessor
    static tokenizer_class = AutoTokenizer

    async _call(text, images = null, ...args) {
        let image_inputs, image_grid_thw;

        if (images) {
            image_inputs = await this.image_processor(images);
            image_grid_thw = image_inputs.image_grid_thw;
        }

        if (image_grid_thw) {
            // Dynamic placeholder replacement for multi-image handling
            const image_grid_thw_list = image_grid_thw.tolist();
            text = text.map(t => {
                while (t.includes("<|image_pad|>")) {
                    const prod = Number(image_grid_thw_list[index++].reduce((a, b) => a * b, 1n));
                    t = t.replace("<|image_pad|>", "<|placeholder|>".repeat(Math.floor(prod / merge_length)));
                }
                return t.replaceAll("<|placeholder|>", "<|image_pad|>");
            });
        }

        const text_inputs = this.tokenizer(text);
        return { ...text_inputs, ...image_inputs };
    }
}
```

