 * ```javascript
 * const pipe = await pipeline('image-text-to-text', 'mozilla/distilvit');
 * const url = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg';
 * const messages = [{ role: 'user', content: [{ type: 'image' }, { type: 'text', text: 'What do you see?' }] }];
 * const output = await pipe(url, messages);
 * // [{ generated_text: 'Two cats are resting comfortably on a couch.' }]
